<?php $metaTitle='Verify Certificate'; include __DIR__.'/includes/header.php'; $cert=null; if($_SERVER['REQUEST_METHOD']==='POST'){ $code=sanitize($_POST['verification_id']); $q=$db->prepare('SELECT c.verification_id,c.issue_date,c.status,s.full_name,co.title course_name FROM certificates c JOIN students s ON s.id=c.student_id JOIN courses co ON co.id=c.course_id WHERE c.verification_id=? LIMIT 1'); $q->execute([$code]); $cert=$q->fetch(); }
?>
<section class="container py-5" style="max-width:700px"><h1>Certificate Verification</h1><form method="post" class="d-flex gap-2 mb-4"><input name="verification_id" class="form-control" placeholder="Enter LEXAI-2026-0001" required><button class="btn btn-primary">Verify</button></form><?php if($_SERVER['REQUEST_METHOD']==='POST'): ?><?php if($cert): ?><div class="card card-body"><p><strong>Student:</strong> <?=e($cert['full_name'])?></p><p><strong>Course:</strong> <?=e($cert['course_name'])?></p><p><strong>Issue Date:</strong> <?=e($cert['issue_date'])?></p><p><strong>Status:</strong> <?=e(ucfirst($cert['status']))?></p></div><?php else:?><div class="alert alert-danger">Invalid certificate ID.</div><?php endif; endif;?></section>
